        {children}
      </Anchor>
    ),
    ul: ({ node: _node, ...props }) => (
      <ul style={{ paddingLeft: 20, marginTop: 4, marginBottom: 4, color }} {...props} />
    ),
    ol: ({ node: _node, ...props }) => (
      <ol style={{ paddingLeft: 20, marginTop: 4, marginBottom: 4, color }} {...props} />
    ),
    li: ({ node: _node, ...props }) => (
