          <IconTool size={14} style={{ flexShrink: 0, color: 'var(--mantine-color-gray-6)' }} />
          <Badge size="sm" variant="light" color="gray">
            {entry.toolName}
          </Badge>
          {summary && (
            <Code style={{ fontSize: 11, wordBreak: 'break-all' }}>
              {summary}
            </Code>
          )}
        </Group>
      </Paper>
    </Group>
  )
}

